module.exports = /*#__PURE__*/JSON.parse('{"personal":{"name":"Heitor Cambre García","role":"Software Engineering Student | Backend / Full Stack","location":"A Coruña, Spain","summary":"Soy estudiante de Ingeniería Informática con un fuerte interés en el desarrollo de software y una base sólida en ingeniería del software. He desarrollado proyectos completos trabajando en backend, frontend y bases de datos, lo que me ha permitido adquirir una visión integral del desarrollo de aplicaciones.\\n\\nAdemás de los proyectos académicos, desarrollo proyectos propios a partir de ideas que considero útiles o interesantes, lo que me permite experimentar con nuevas tecnologías, mejorar mis habilidades técnicas y aplicar conceptos de ingeniería del software en contextos reales.\\n\\nDisfruto diseñando soluciones robustas y bien estructuradas, y me interesa especialmente seguir creciendo en áreas como la ciberseguridad y el uso de la inteligencia artificial como herramienta de apoyo al desarrollo de software, enfocándome en mejorar la productividad y explorar hasta qué punto puede ayudar a crear soluciones reales de forma más eficiente, aplicándola en algunos de los proyectos que estoy desarrollando."},"education":[{"degree":"Grado en Ingeniería Informática","institution":"Universidade da Coruña (UDC)","status":"En curso","expected_graduation":"2026"}],"skills":{"languages_core":["C","C#","Java","JavaScript","SQL","HTML","CSS"],"languages_secondary":["Dart"],"frameworks":["Spring Boot","Spring Security","React","Redux",".NET / ASP.NET","Entity Framework","Hibernate / JPA"],"testing":["JUnit"],"authentication":["JWT"],"databases":["PostgreSQL","MySQL"],"tools":["Git, GitHub","Docker","Maven, Yarn, npm","Postman","Linux, Bash","Visual Studio, IntelliJ IDEA, VS Code"],"concepts":["Algoritmos y estructuras de datos","Programación orientada a objetos","Concurrencia y paralelismo","Arquitecturas MVC y MVP","Desarrollo de aplicaciones completas","APIs REST","Bases de datos relacionales","Control de versiones"]},"projects":[{"name":"Synapse","type":"Proyecto personal","status":"En desarrollo","started":"Inicio del proyecto: febrero de 2026","description":"Aplicación web personal orientada a dar salida cómoda a todo lo que solemos dejar \\"para después\\": notas, enlaces y fragmentos que acaban perdiéndose. El flujo ayuda a clasificar y recuperar esa información sin fricción y usa notificaciones para recordar pendientes y material sin revisar. Sigue en evolución activa: en el horizonte hay funcionalidades para usos más amplios, como flashcards asociadas a las carpetas que el usuario define.","responsibilities":[],"technologies":["Java","Spring Boot","Spring Security","PostgreSQL","Flyway","React","TypeScript","Vite","Docker","Docker Compose","JWT","REST API","Ollama AI"],"highlights":["Full stack productivo: API en Spring Boot (Java) y cliente en React + TypeScript (Vite), aplicación web con flujo real de uso (captura → bandeja → procesamiento → conocimiento).","Experiencia de producto web: interfaz responsive, rutas y estado de aplicación coherentes; internacionalización (i18n) para usar la app en varios idiomas desde el navegador.","Datos y despliegue: PostgreSQL con migraciones (Flyway), modelo de dominio con bandeja, conocimiento y notificaciones; documentación y Docker Compose para levantar el stack.","IA en el flujo: pipeline de procesamiento asíncrono con integración Ollama (configurable), con enfoque en resiliencia cuando el modelo o la red fallan.","Seguridad y operación: autenticación JWT, manejo cuidadoso de secretos y errores API con trazabilidad (trace id), sin exponer detalles internos al cliente."],"github":"https://github.com/heitorcg5/Synapse"},{"name":"Tienda de comercio electrónico (.NET)","type":"Proyecto académico en grupo","status":"Terminado","github":"https://github.com/heitorcg5/MaD-.NET.git","description":"Aplicación web de comercio electrónico desarrollada en C# y .NET con arquitectura por capas, orientada a cubrir un flujo real de tienda online de extremo a extremo: catálogo de productos con subtipos y categorías, búsqueda filtrada, carrito, proceso de compra y gestión de pedidos. El proyecto fue evaluado con una calificación de 10/10 por profesorado de la facultad.","responsibilities":["Desarrollo Full Stack (backend, frontend y modelo de datos)","Integración de la API de Google para inicio de sesión (OAuth 2.0)","Diseño e implementación del sistema de nube de etiquetas para comentarios","Escritura de pruebas de integración","Trabajo colaborativo siguiendo una arquitectura por capas"],"technologies":["C#",".NET","Entity Framework","PostgreSQL","OAuth 2.0 (Google Login)"],"highlights":["Autenticación y autorización con roles, contraseñas cifradas e integración de login con Google (OAuth 2.0)","Gestión de catálogo con productos por subtipos y categorías, incluyendo búsqueda por texto y filtrado por categoría","Proceso de compra completo: carrito de sesión, checkout, generación de pedidos e histórico con líneas de pedido y precios unitarios","Funcionalidades Web 2.0: comentarios de producto, etiquetado y nube de etiquetas para mejorar clasificación y recuperación","Pruebas de integración automatizadas sobre servicios de la capa modelo y calificación final de 10/10"]},{"name":"Aplicación de rutinas de gimnasio","type":"Proyecto académico en grupo","status":"Terminado","description":"Aplicación web Full Stack para rutinas de gimnasio, estadísticas y métricas de usuario. Equipo de siete con Scrum, Kanban y XP; participación activa en un entorno colaborativo donde me desenvolví con soltura.","responsibilities":["Scrum, Kanban y XP en equipo de siete; coordinación y comunicación durante el proyecto","Sistema completo de estadísticas con múltiples tipos de gráficos (líneas, radar) y filtros temporales","Implementación de gestión de equipamiento y grupos musculares","Creación del sistema de listado y visualización de rutinas disponibles","Desarrollo de funcionalidad de bloqueo de usuarios","Preparación y carga de datos de prueba en base de datos para validación funcional","Corrección de bugs y mejoras en funcionalidades existentes"],"technologies":["Java","Spring Boot","Spring Security","JWT","React","React Router","JavaScript","Recharts","PostgreSQL","Docker","Kubernetes","Maven","Yarn"],"highlights":["Metodologías ágiles (Scrum, Kanban, XP) en equipo de siete; buena coordinación y entorno donde me sentí muy cómodo","Sistema completo de estadísticas con múltiples tipos de gráficos (líneas, radar) y filtros temporales","Autenticación y autorización con JWT y Spring Security","Gestión de usuarios con sistema de bloqueo y seguimiento de coaches","Visualización de estadísticas mediante gráficos con Recharts","Despliegue con Docker"]}],"interests":[{"area":"Desarrollo de software y arquitectura","description":"Interés en diseñar y desarrollar aplicaciones robustas, escalables y bien estructuradas, con especial atención a la arquitectura, la lógica de negocio y la calidad del software."},{"area":"Ciberseguridad","description":"Interés en la seguridad de aplicaciones web, incluyendo autenticación, autorización, cifrado de contraseñas y buenas prácticas de desarrollo seguro."},{"area":"Uso de inteligencia artificial en el desarrollo","description":"Uso consciente de herramientas de IA para aumentar la productividad, apoyar el diseño de soluciones, generar pruebas y mejorar la calidad del código."}],"languages":[{"language":"Español","level":"Nativo"},{"language":"Gallego","level":"Nativo"},{"language":"Inglés","level":"C1 (certificado por Cambridge)"}],"links":{"github":"https://github.com/heitorcg5","linkedin":"https://www.linkedin.com/in/heitorcambregarcia/","email":"heitorcambre@gmail.com","portfolio":"https://heitorcambregarcia.com/"}}');

